struct X {
    i: u8,
    j: u8,
}

struct Y {
    x: X,
}

impl X {
    #[verifier::type_invariant]
    spec fn the_inv(&self) -> bool {
        0 <= self.i < 15
    }
}

impl Y {
    #[verifier::type_invariant]
    spec fn the_inv(&self) -> bool {
        20 <= self.x.j < 30
    }
}

